(14, 'images/case-studies/QUEST_Mockup.webp', 'images/case-studies/background/after_quest.webp', 'Redeisgn & Develop Quest  Website', ' Transform the platform into a modern, responsive, and user-focused website that better represents the university’s identity and serves the needs of students, faculty, and visitors.', 'active', 'https://qonkar.com/case-studies/quest-official', '2025-10-09 08:00:24', '2025-12-18 12:00:13'),
