INSERT INTO `jobs` (`job_id`, `job_title`, `slug`, `job_type`, `location`, `job_description`, `job_status`, `created_at`, `updated_at`) VALUES
(9, 'Social Media Manager ', 'social-media-manager-', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; Social Media Manager</strong> We&rsquo;re looking for creative Social Media Interns who can help us manage, grow, and create impact for brands online. If you live and breathe Instagram trends, TikTok reels, LinkedIn posts, and Facebook ads, this role is made for you.</p>\r\n<p><strong>Key Responsibilities</strong></p>\r\n<p>&bull; Plan and schedule content calendars across all social platforms.</p>\r\n<p>&bull; Assist in content creation &ndash; captions, hashtags, storytelling, and campaign ideas.&nbsp;</p>\r\n<p>&bull; Monitor engagement metrics, comments, and community interactions.</p>\r\n<p>&bull; Work with the design and video teams to launch eye-catching posts &amp; reels.</p>\r\n<p>&bull; Research latest trends, memes, and industry updates for content ideas.</p>\r\n<p>&bull; Help run paid ad campaigns and track performance.</p>\r\n<p>&bull; Prepare weekly reports on account growth and engagement.</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Basic knowledge of Facebook, Instagram, LinkedIn, TikTok, and Twitter/X.</p>\r\n<p>&bull; Creativity with content writing and trend adaptation.</p>\r\n<p>&bull; Passion for branding, marketing, and storytelling.</p>\r\n<p>&bull; Ability to analyze insights and think strategically.</p>\r\n<p>&bull; Proactive, team player, and eager to learn.&nbsp;</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Hands-on experience managing real brand accounts.</p>\r\n<p>&bull; Learn professional tools like Meta Business Suite, Canva, and Buffer. &bull; Exposure to global clients and campaigns.</p>\r\n<p>&bull; Mentorship from digital marketing managers.</p>\r\n<p>&bull; Portfolio boost with live campaign results.</p>\r\n<p>&bull; Opportunity for a full-time role after internship.&nbsp;</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 12:48:20', '2025-12-16 09:41:10'),
(10, 'Graphics Designer', 'graphics-designer', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; Social Media Manager</strong></p>\r\n<p>We&rsquo;re looking for creative Social Media Interns who can help us manage, grow, and create impact for brands online. If you live and breathe Instagram trends, TikTok reels, LinkedIn posts, and Facebook ads, this role is made for you.&nbsp;</p>\r\n<p><strong>Key Responsibilities</strong></p>\r\n<p>&bull; Plan and schedule content calendars across all social platforms.</p>\r\n<p>&bull; Assist in content creation &ndash; captions, hashtags, storytelling, and campaign ideas.</p>\r\n<p>&bull; Monitor engagement metrics, comments, and community interactions.</p>\r\n<p>&bull; Work with the design and video teams to launch eye-catching posts &amp; reels.</p>\r\n<p>&bull; Research latest trends, memes, and industry updates for content ideas.</p>\r\n<p>&bull; Help run paid ad campaigns and track performance.</p>\r\n<p>&bull; Prepare weekly reports on account growth and engagement.&nbsp;</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Basic knowledge of Facebook, Instagram, LinkedIn, TikTok, and Twitter/X.</p>\r\n<p>&bull; Creativity with content writing and trend adaptation.</p>\r\n<p>&bull; Passion for branding, marketing, and storytelling.</p>\r\n<p>&bull; Ability to analyze insights and think strategically.</p>\r\n<p>&bull; Proactive, team player, and eager to learn.&nbsp;</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Hands-on experience managing real brand accounts.</p>\r\n<p>&bull; Learn professional tools like Meta Business Suite, Canva, and Buffer.</p>\r\n<p>&bull; Exposure to global clients and campaigns.</p>\r\n<p>&bull; Mentorship from digital marketing managers.</p>\r\n<p>&bull; Portfolio boost with live campaign results.&nbsp;</p>\r\n<p>&bull; Opportunity for a full-time role after internship.&nbsp;</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 12:55:48', '2025-12-16 09:41:10'),
(12, 'Copywriter', 'copywriter', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; Copywriter</strong></p>\r\n<p>We&rsquo;re looking for creative Copywriting Interns who can turn ideas into powerful words. If you have a passion for writing, storytelling, and creating content that connects with people, this internship will give you professional exposure to both advertising and software industries.&nbsp;</p>\r\n<p><strong>Key Responsibilities</strong></p>\r\n<p>&bull; Write engaging copy for social media posts, ads, blogs, and websites.</p>\r\n<p>&bull; Collaborate with designers and social media teams to craft impactful campaigns.</p>\r\n<p>&bull; Ensure all content aligns with brand voice and messaging.</p>\r\n<p>&bull; Assist in writing email marketing campaigns and product descriptions.</p>\r\n<p>&bull; Research industry trends and translate them into easy-to-read content.</p>\r\n<p>&bull; Proofread and edit existing content for clarity, grammar, and tone.</p>\r\n<p>&bull; Contribute to creative brainstorming sessions with the marketing team.&nbsp;</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Strong command of English writing and grammar.</p>\r\n<p>&bull; Creativity with a knack for storytelling and brand communication. &bull; Ability to adapt tone and style for different audiences.</p>\r\n<p>&bull; Familiarity with SEO-friendly content writing is a plus.</p>\r\n<p>&bull; Curiosity and willingness to learn the art of persuasive writing.</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Practical experience in copywriting for global audiences.</p>\r\n<p>&bull; Exposure to real projects with measurable impact.</p>\r\n<p>&bull; Mentorship from advertising and branding experts.</p>\r\n<p>&bull; Opportunity to build a professional writing portfolio.</p>\r\n<p>&bull; Pathway to a full-time role after internship based on performance.&nbsp;</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 13:05:48', '2025-12-16 09:41:10'),
(13, 'Content Creator / Writer', 'content-creator-/-writer', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; Content Creator / Writer</strong></p>\r\n<p>&nbsp;We&rsquo;re looking for Content Creator / Writer Interns who can craft engaging stories and ideas that resonate with audiences. From social media posts to blogs, campaigns, and scripts, you&rsquo;ll learn to create content that educates, entertains, and converts.</p>\r\n<p>&nbsp;<strong>Key Responsibilities</strong></p>\r\n<p>&bull; Write and develop creative content for social media, blogs, websites, and campaigns.</p>\r\n<p>&bull; Assist in scriptwriting for reels, ads, and promotional videos.</p>\r\n<p>&bull; Research industry trends and produce original, audience-focused content.</p>\r\n<p>&bull; Work closely with designers and marketing teams to create cohesive campaigns.</p>\r\n<p>&bull; Ensure all content is clear, concise, and aligned with brand tone.</p>\r\n<p>&bull; Brainstorm fresh content ideas for digital platforms and marketing campaigns.</p>\r\n<p>&bull; Edit and proofread content for grammar, readability, and impact.&nbsp;</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Strong command of English writing and creativity.</p>\r\n<p>&bull; Interest in storytelling, branding, and marketing.</p>\r\n<p>&bull; Familiarity with social media trends and content types.</p>\r\n<p>&bull; Ability to adapt writing style for different formats and platforms.</p>\r\n<p>&bull; Passion to learn content marketing and digital storytelling.&nbsp;</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Experience in content writing across multiple industries.</p>\r\n<p>&bull; Opportunity to work on global-level projects and campaigns.</p>\r\n<p>&bull; Mentorship from content strategists and marketing professionals. &bull; A strong portfolio with published content pieces.</p>\r\n<p>&bull; A clear pathway to full-time content roles after internship.</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 14:24:12', '2025-12-16 09:41:10'),
(14, 'SEO Specialist', 'seo-specialist', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; SEO Specialist</strong></p>\r\n<p>We&rsquo;re looking for SEO Interns who are eager to learn how websites rank, attract traffic, and convert visitors into customers. This role is perfect for someone who wants to build a career in digital marketing, analytics, and growth strategies while working with real clients.</p>\r\n<p><strong>Key Responsibilities </strong></p>\r\n<p>&bull; Conduct keyword research and competitor analysis.</p>\r\n<p>&bull; Optimize website content, meta titles, and descriptions.&nbsp;</p>\r\n<p>&bull; Assist in building on-page and off-page SEO strategies.</p>\r\n<p>&bull; Monitor site performance using tools like Google Analytics &amp; Search Console.</p>\r\n<p>&bull; Help improve website speed, structure, and user experience.</p>\r\n<p>&bull; Support in generating SEO reports for campaigns and clients.</p>\r\n<p>&bull; Stay updated with Google algorithm updates &amp; SEO trends.</p>\r\n<p>&nbsp;<strong>What We Expect</strong></p>\r\n<p>&bull; Basic knowledge of SEO principles (on-page/off-page).</p>\r\n<p>&bull; Familiarity with Google tools (Analytics, Search Console, Keyword Planner).</p>\r\n<p>&bull; Interest in content optimization and ranking strategies.</p>\r\n<p>&bull; Analytical thinking with attention to detail.</p>\r\n<p>&bull; Willingness to learn advanced SEO techniques.</p>\r\n<p>&nbsp;<strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Hands-on experience in real SEO campaigns.</p>\r\n<p>&bull; Practical training on industry-standard tools.</p>\r\n<p>&bull; Learn how SEO drives traffic, leads, and conversions.</p>\r\n<p>&bull; Mentorship from digital marketing experts.</p>\r\n<p>&bull; Opportunity to build a portfolio of SEO results.</p>\r\n<p>&bull; Pathway to a full-time role after internship.</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 14:27:34', '2025-12-16 09:41:10'),
(15, 'E-Commerce Manager', 'e-commerce-manager', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong></p>\r\n<p>Internship Role &ndash; E-Commerce Manager We&rsquo;re looking for E-Commerce Interns who want to understand how online businesses grow and scale. If you&rsquo;re passionate about Shopify, online stores, product management, and digital sales, this role gives you the chance to gain practical, hands-on experience.&nbsp;</p>\r\n<p><strong>Key Responsibilities</strong></p>\r\n<p>&bull; Manage and update product listings, categories, and descriptions on Shopify and other platforms.</p>\r\n<p>&bull; Coordinate with designers for product images, banners, and store visuals.</p>\r\n<p>&bull; Monitor orders, payments, and customer queries on e-commerce dashboards.</p>\r\n<p>&bull; Work with the marketing team to launch discounts, promotions, and bundle deals.</p>\r\n<p>&bull; Assist in inventory tracking and sync with stock management.</p>\r\n<p>&bull; Analyze sales reports and customer behavior for optimization.</p>\r\n<p>&bull; Research global e-commerce trends and suggest improvements.&nbsp;</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Basic knowledge of Shopify, WooCommerce, or other e-commerce platforms.</p>\r\n<p>&bull; Interest in digital sales, online business, and product marketing.</p>\r\n<p>&bull; Strong attention to detail in product listings and pricing.</p>\r\n<p>&bull; Good communication and problem-solving skills.&nbsp;</p>\r\n<p>&bull; Willingness to learn analytics and conversion optimization.</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Experience in managing live e-commerce stores.</p>\r\n<p>&bull; Knowledge of Shopify store optimization and management.</p>\r\n<p>&bull; Insights into customer behavior, sales funnels, and digital retail.</p>\r\n<p>&bull; Mentorship from e-commerce specialists.</p>\r\n<p>&bull; Build a portfolio with real case studies of store growth.</p>\r\n<p>&bull; Opportunity to move into a permanent role after internship.</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 14:30:45', '2025-12-16 09:41:10'),
(16, 'Videographer', 'videographer', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; Videographer</strong></p>\r\n<p>We&rsquo;re looking for Videographer Interns who are passionate about capturing stories and bringing them to life through visuals. If you love shooting videos, experimenting with camera angles, and creating content for brands, this internship is your chance to gain professional experience with real projects.&nbsp;</p>\r\n<p><strong>Key Responsibilities</strong></p>\r\n<p>&bull; Capture high-quality videos for social media, ads, events, and campaigns.</p>\r\n<p>&bull; Plan and shoot content for corporate, creative, and product-focused projects.</p>\r\n<p>&bull; Work with the content team to execute scripts and storyboards.</p>\r\n<p>&bull; Manage camera equipment, lighting setups, and audio for shoots.</p>\r\n<p>&bull; Collaborate with editors to ensure smooth post-production workflow.</p>\r\n<p>&bull; Experiment with creative shots and bring fresh ideas to projects.</p>\r\n<p>&bull; Ensure all content aligns with brand guidelines and quality standards.&nbsp;</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Basic knowledge of DSLRs, mobile videography, and lighting setups.</p>\r\n<p>&bull; Interest in storytelling, content creation, and visual branding.</p>\r\n<p>&bull; Ability to follow directions and work with teams.</p>\r\n<p>&bull; Familiarity with video trends on platforms like Instagram, TikTok, and YouTube.</p>\r\n<p>&bull; Passion to learn professional videography and brand filmmaking.&nbsp;</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Hands-on experience with live projects and client shoots.</p>\r\n<p>&bull; Exposure to agency-level video production.</p>\r\n<p>&bull; Mentorship from creative managers and content leads.</p>\r\n<p>&bull; A chance to build a professional video portfolio.</p>\r\n<p>&bull; Pathway to a permanent role after internship.&nbsp;</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 14:33:57', '2025-12-16 09:41:10'),
(17, 'Business Development Manager', 'business-development-manager', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; Business Development Manager</strong></p>\r\n<p>&nbsp;We&rsquo;re looking for Business Development Interns who are eager to learn how to build relationships, close deals, and expand business opportunities. This internship is ideal for those who want to step into the world of sales, strategy, and client management with hands-on professional training.</p>\r\n<p><strong>Key Responsibilities</strong></p>\r\n<p>&bull; Research and identify potential clients, industries, and business opportunities.</p>\r\n<p>&bull; Assist in preparing business proposals, presentations, and sales pitches.</p>\r\n<p>&bull; Support the team in client outreach via email, LinkedIn, and calls.</p>\r\n<p>&bull; Help maintain and update the sales pipeline and CRM records.</p>\r\n<p>&bull; Collaborate with the marketing team for lead generation campaigns.</p>\r\n<p>&bull; Attend meetings (virtual/on-site) and assist in client communication. &bull; Prepare reports on sales activities and market insights.</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Strong communication and interpersonal skills.</p>\r\n<p>&bull; Interest in sales, business growth, and client management.</p>\r\n<p>&bull; Ability to analyze data and spot opportunities.</p>\r\n<p>&bull; Familiarity with MS Office / Google Workspace tools.</p>\r\n<p>&bull; Proactive attitude and willingness to learn fast.</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Practical exposure to B2B and B2C business development.</p>\r\n<p>&bull; Learn sales strategy, negotiation, and client relationship building.</p>\r\n<p>&bull; Hands-on experience in proposal writing and pitching.</p>\r\n<p>&bull; Mentorship from business development experts.</p>\r\n<p>&bull; Build a foundation for a career in sales, business development, or consulting.</p>\r\n<p>&bull; A chance to move into a full-time role after internship.</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 14:36:13', '2025-12-16 09:41:10'),
(18, 'Video Editor', 'video-editor', 'Internship', 'Karachi & Nawabshah Offices', '<p>Duration: <strong>6 Months</strong> <strong>Internship Role &ndash; Video Editor</strong></p>\r\n<p>We&rsquo;re looking for Video Editing Interns who can transform raw footage into impactful, engaging stories. From short-form reels to brand films and corporate videos, this role is your chance to sharpen editing skills and work with real client campaigns.&nbsp;</p>\r\n<p><strong>Key Responsibilities</strong></p>\r\n<p>&bull; Edit social media reels, ads, event coverage, and promotional videos.</p>\r\n<p>&bull; Add animations, captions, transitions, and sound effects to enhance storytelling.</p>\r\n<p>&bull; Work with videographers and creative managers to execute campaign ideas.</p>\r\n<p>&bull; Ensure videos align with brand guidelines and marketing goals.</p>\r\n<p>&bull; Optimize video content for different platforms (Instagram, TikTok, YouTube, LinkedIn).</p>\r\n<p>&bull; Assist in creating motion graphics and simple visual effects.</p>\r\n<p>&bull; Manage project timelines and deliver quality edits on schedule.&nbsp;</p>\r\n<p><strong>What We Expect</strong></p>\r\n<p>&bull; Basic knowledge of tools like Adobe Premiere Pro, After Effects, Final Cut Pro, or CapCut.</p>\r\n<p>&bull; Creative eye for pacing, flow, and visual storytelling.</p>\r\n<p>&bull; Familiarity with social media trends and editing styles.&nbsp;</p>\r\n<p>&bull; Ability to collaborate in a team environment.</p>\r\n<p>&bull; Passion to learn professional video editing workflows.&nbsp;</p>\r\n<p><strong>What You&rsquo;ll Gain</strong></p>\r\n<p>&bull; Experience editing live brand campaigns and projects.</p>\r\n<p>&bull; Learn how to balance creativity with marketing goals.</p>\r\n<p>&bull; Build a professional video portfolio with published work.</p>\r\n<p>&bull; Guidance from creative and marketing experts.</p>\r\n<p>&bull; A clear pathway to a full-time editing role after internship.&nbsp;</p>\r\n<p><strong>Office Locations</strong></p>\r\n<p>&bull; Karachi Office: Kolachi IT Park, Rashid Minhas Road, Karachi.</p>\r\n<p>&bull; Nawabshah Office: Software Technology Park, QUEST, Nawabshah.</p>', 'open', '2025-09-26 14:49:54', '2025-12-16 10:22:59');

