(26, 'urooj', 'uroojzehra351@gmail.com', '03243608510', '', '500-1000', 'To\r\nThe HR Manager,\r\nQONKAR Technologoies,\r\n\r\n\r\nSubject: Application for Internship as a Web Business Developer\r\n\r\nDear Sir/Madam,\r\n\r\nI am writing to express my interest in applying for the Web Business Developer Internship at your esteemed organization.  and I am eager to gain practical experience in web development and business strategy.\r\n\r\nI have a strong foundation in web technologies such as HTML, CSS, JavaScript, and PHP, along with basic knowledge of digital marketing, SEO, and e-commerce strategies. I am passionate about combining technical skills with business insights to build user-friendly, growth-oriented web solutions.\r\n\r\nThis internship opportunity will allow me to apply my academic learning to real-world projects and further develop my skills in web design, client communication, and business development. I am confident that my enthusiasm, creativity, and commitment will make a valuable contribution to your team.\r\n\r\nI would be grateful if you could consider my application for this internship. I am looking forward to the opportunity to learn and grow under your guidance.\r\n\r\nThank you for your time and consideration.\r\n\r\nYours faithfully,\r\nUrooj Mehar\r\n03243608510\r\nuroojzehra351@gmail.com', 'unread', '2025-10-23 06:32:26'),
(27, 'Huzaifa Haris', 'huzaifaharis415@gmail.com', '033333333', 'asdfa', '500-1000', 'For Checking the Email is working', 'unread', '2025-10-23 11:08:24'),
(28, 'Gary Charles', 'g_c@dominatingkeywords.com', '8054002077', 'DominatingKeywords.com', '500-1000', 'I am not offering SEO or Pay Per Click Advertising services.\r\nThis is something entirely different.\r\nLet me demonstrate how it works and you\'ll be pleasantly surprised by the results.\r\nSimply send us your desired keywords or fill online quote form on our website, and your website will instantly appear at the top of Google and Bing search results, without any Pay Per Click charges.', 'unread', '2025-10-29 22:24:57'),
(29, 'ABC', 'abc@abc.com', '', '', '500-1000', 'Testing...', 'unread', '2025-11-04 11:25:51'),
(30, 'Huzaifa Haris', 'huzaifaharis415@gmail.com', '03103244179', 'Just Checking', '500-1000', 'Just For Checking Email System', 'unread', '2025-11-13 09:38:04'),
(31, 'Nathaniel Brooks', 'nathaniel.reid@jmailservice.com', '8054002077', 'The Fastest Way to Get More Clicks', '500-1000', 'Let\'s get your business showing up before competitors when people search for your services. Setup takes less than a day.\r\nWhat\'s the best number to reach you?', 'unread', '2025-11-14 11:28:10'),
(32, 'Alina', 'ahmedalina971@gmail.com', '031100441445', 'Just Checking Email Format', '500-1000', 'I\'m Just Checking the Email Formatting :-)', 'unread', '2025-11-21 09:34:49'),
(33, 'Marcus Palmer', 'marcus.palmer@jmailservice.com', '8054002077', 'Get Found First - Easy 24-Hour Setup', '500-1000', 'Our system gets your company listed on top of search results almost instantly - no long SEO process, no delay.\r\nCan I walk you through it on a short call?', 'unread', '2025-12-08 15:25:40'),
